INSERT INTO pizzas (nome, description, price, url_image) VALUES('Margherita', 'La regina delle pizze: pomodoro, mozzarella fior di latte, basilico fresco e olio EVO.', 7.50, 'https://it.itca.it/wp-content/uploads/2021/03/pizza-margherita.jpg'),('Marinara', 'Semplice e autentica: pomodoro, aglio, origano e olio extravergine d''oliva.', 6.00, 'https://www.pizzanapoletana.org/struttura/pizze/marinara.jpg'),('Diavola', 'Per chi ama il piccante: pomodoro, mozzarella e salame piccante calabrese.', 9.00, 'https://primochef.it/wp-content/uploads/2020/04/SH_pizza_alla_diavola.jpg'),('Quattro Formaggi', 'Un mix cremoso di mozzarella, gorgonzola, fontina e parmigiano reggiano.', 10.50, 'https://www.silviocicchi.com/pizzachef/wp-content/uploads/2015/01/4f1.jpg'),('Capricciosa', 'Ricca e varia: pomodoro, mozzarella, prosciutto cotto, funghi, carciofini e olive nere.', 11.00, 'https://www.pizzanapoletana.org/struttura/pizze/capricciosa.jpg'),('Bufalina', 'L''eccellenza campana: pomodoro San Marzano e mozzarella di bufala DOP a crudo.', 9.50, 'https://www.scattidigusto.it/wp-content/uploads/2020/06/pizza-margherita-bufala.jpg'),('Ortolana', 'Leggerezza e gusto: mozzarella e verdure grigliate di stagione (zucchine, melanzane, peperoni).', 9.00, 'https://www.pizzanapoletana.org/struttura/pizze/vegetariana.jpg'),('Salsiccia e Friarielli', 'Il classico napoletano: mozzarella, salsiccia fresca e friarielli saltati in padella.', 10.00, 'https://www.pizzanapoletana.org/struttura/pizze/salsiccia_friarielli.jpg'),('Boscaiola', 'Profumo di bosco: mozzarella, funghi champignon e salsiccia sbriciolata.', 9.50, 'https://www.pizzanapoletana.org/struttura/pizze/boscaiola.jpg'),('Pistacchio e Mortadella', 'Gusto gourmet: base bianca con mozzarella, mortadella Bologna IGP e granella di pistacchio.', 12.50, 'https://www.pizzanapoletana.org/struttura/pizze/pistacchio_mortadella.jpg');